#include <iostream>
#include <vector>
#include <numeric>

using namespace std;

bool canPartition(vector<int>& nums)
{
    int total = accumulate(nums.begin(), nums.end(), 0);
    if (total % 2 != 0) return false;
    int target = total / 2;

    int n = nums.size();
    vector<vector<bool>> dp(n + 1, vector<bool>(target + 1, false));
    for (int i = 0; i <= n; i++) dp[i][0] = true;

    for (int i = 1; i <= n; i++)
        for (int w = 0; w <= target; w++)
        {
            dp[i][w] = dp[i - 1][w];
            if (nums[i - 1] <= w) dp[i][w] = dp[i][w] || dp[i - 1][w - nums[i - 1]];
        }

    return dp[n][target];
}

int main()
{
    vector<int> nums = {1, 5, 11, 5};
    cout << boolalpha << canPartition(nums);

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

using namespace std;

bool canPartition(vector<int>& nums)
{
    int total = accumulate(nums.begin(), nums.end(), 0);
    if (total % 2 != 0) return false;
    int target = total / 2;

    vector<bool> dp(target + 1, false);
    dp[0] = true;

    for (int num : nums)
        for (int w = target; w >= num; w--)
            dp[w] = dp[w] || dp[w - num];

    return dp[target];
}

int main()
{
    vector<int> nums = {1, 5, 11, 5};
    cout << boolalpha << canPartition(nums);

    return 0;
}

